Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class PlatformAndEnvironmentTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public PlatformAndEnvironmentTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only (skipped on Linux/macOS)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        using var key = Microsoft.Win32.Registry.CurrentUser.OpenSubKey(@"SOFTWARE\MyApp");
        Assert.IsNotNull(key);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_UsesGpuAcceleration()
    {
        var result = GpuRenderer.RenderTestFrame();
        Assert.IsTrue(result.UsedHardwareAcceleration);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync(
            "Seattle", _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Cleanup temp files even on failure
    [TestMethod]
    public void Export_CreatesValidFile()
    {
        _tempFile = Path.GetTempFileName();
        Exporter.WriteTo(_tempFile);
        Assert.IsTrue(new FileInfo(_tempFile).Length > 0);
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Key points:**

| Scenario | Attribute/Pattern | MSTest Version |
|----------|-------------------|----------------|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retries | `[Retry(3)]` | 3.9+ |
| Guaranteed cleanup | `[TestCleanup]` method | All versions |

- `[TestCleanup]` runs after every test regardless of pass/fail, making it ideal for temp file deletion.
- `[Retry]` should only be used for genuinely external flakiness—not to mask race conditions.
- `CICondition` detects common CI environment variables (e.g., `CI`, `TF_BUILD`, `GITHUB_ACTIONS`) automatically.
